import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { useParams, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";

function TakeTest() {
  const { testId } = useParams();
  const user = useSelector((state) => state.auth.user);
  const navigate = useNavigate();
  const [test, setTest] = useState(null);
  const [answers, setAnswers] = useState([]);

  useEffect(() => {
    async function fetchTest() {
      try {
        const response = await fetch(`http://localhost:3001/tests/${testId}`);
        if (!response.ok) {
          toast.error("Тест не найден!");
          navigate("/courses");
          return;
        }
        const data = await response.json();
        if (!data.courseId || !user.courseId || data.courseId !== user.courseId) {
          toast.error("У вас нет доступа к этому тесту!");
          navigate("/courses");
          return;
        }
        setTest(data);
        // Инициализируем answers как массив объектов с questionId и answerIndex
        const initialAnswers = data.questions.map(question => ({
          questionId: question.id,
          answerIndex: null
        }));
        setAnswers(initialAnswers);
      } catch (error) {
        toast.error("Ошибка загрузки теста");
      }
    }
    fetchTest();
  }, [testId, user.courseId, navigate]);

  const handleAnswerChange = (questionId, answerIndex) => {
    setAnswers(prevAnswers =>
      prevAnswers.map(answer =>
        answer.questionId === questionId
          ? { ...answer, answerIndex }
          : answer
      )
    );
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!test) {
      toast.error("Тест не загружен!");
      return;
    }
    if (answers.some(answer => answer.answerIndex === null)) {
      toast.error("Ответьте на все вопросы!");
      return;
    }

    const correctAnswers = test.questions.map(q => q.correctAnswerIndex);
    const score = (answers.reduce((acc, answer, index) => {
      const questionIndex = test.questions.findIndex(q => q.id === answer.questionId);
      return acc + (answer.answerIndex === correctAnswers[questionIndex] ? 1 : 0);
    }, 0) / answers.length) * 100;

    try {
      const existingResults = await fetch(
        `http://localhost:3001/test_results?userId=${user.id}&testId=${testId}`
      ).then(res => res.json());

      if (existingResults.length > 0) {
        for (const result of existingResults) {
          await fetch(`http://localhost:3001/test_results/${result.id}`, {
            method: "DELETE",
          });
        }
      }

      const result = {
        userId: user.id,
        testId: parseInt(testId),
        answers: answers.map(a => a.answerIndex),
        score: score.toFixed(2),
        submittedAt: new Date().toISOString(),
      };

      const response = await fetch("http://localhost:3001/test_results", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(result),
      });

      if (response.ok) {
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId: user.id,
            message: `Вы сдали тест "${test.title}" с результатом ${score.toFixed(2)}%.`,
            createdAt: new Date().toISOString(),
          }),
        });
        toast.success("Тест успешно сдан!");
        navigate("/courses");
      } else {
        toast.error("Не удалось сохранить результат теста");
      }
    } catch (error) {
      toast.error("Ошибка при обработке результатов теста");
    }
  };

  if (!test) return <div className="container mt-5"><h2>Загрузка...</h2></div>;

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Тест: {test.title}</h1>
      <div className="card shadow">
        <div className="card-body">
          <form onSubmit={handleSubmit}>
            {test.questions.map((question, qIndex) => {
              const answer = answers.find(a => a.questionId === question.id);
              return (
                <div key={question.id} className="mb-4">
                  <h5>{qIndex + 1}. {question.text}</h5>
                  {question.options.map((option, oIndex) => (
                    <div key={oIndex} className="form-check">
                      <input
                        className="form-check-input"
                        type="radio"
                        name={`question-${question.id}`}
                        id={`question-${question.id}-option-${oIndex}`}
                        value={oIndex}
                        checked={answer?.answerIndex === oIndex}
                        onChange={() => handleAnswerChange(question.id, oIndex)}
                        required
                      />
                      <label
                        className="form-check-label"
                        htmlFor={`question-${question.id}-option-${oIndex}`}
                      >
                        {option}
                      </label>
                    </div>
                  ))}
                </div>
              );
            })}
            <button type="submit" className="btn btn-primary w-100">
              Отправить
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default TakeTest;
